- $1 \le A_i \le 10^9$", "difficulty": "easy", "tags": ["binary-search", "two-pointers", "sorting"], "time_limit_ms": 1000, "memory_limit_kb": 65536, "xp_reward": 10, "reference_cpp": "#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, K;
    cin >> N >> K;

    vector<int> A(N);
    for (int i = 0; i < N; i++) {
        cin >> A[i];
    }

    sort(A.begin(), A.end());

    long long ans = 0;
    int j = 0;

    for (int i = 0; i < N; i++) {
        while (j < N && A[j] - A[i] < K) {
            j++;
        }
        ans += (N - j);
    }

    cout << ans << "\n";

    return 0;
